// boolAttr converts a bool to the aria-pressed string "true"/"false".
func boolAttr(b bool) string {
	if b {
		return "true"
	}
	return "false"
}

// filterStatusStr formats the filter status string (status + remaining days).
func filterStatusStr(v ui.DeviceView) string {
	if v.FilterRemaining != "" {
		return fmt.Sprintf("%s (%s)", v.FilterStatus, v.FilterRemaining)
	}
	return v.FilterStatus
}

// powerButtonExpr produces the data-on:click expression for the power
// toggle. POSTs the inverse of the current power state.
func powerButtonExpr(v ui.DeviceView) string {
	return postActionExpr(
		fmt.Sprintf("/ui/devices/%s/power", v.Name),
		fmt.Sprintf("{on: %t}", !v.Power),
	)
}

// initialCardSignals returns the per-card datastar signals seed as JSON.
// Default-open rules: info=closed, sensors=open, energy=closed,
// schedule=closed. The `alert` CSS class on the <details> handles the
// "this needs attention" visual cue without forcing the panel open.
func initialCardSignals() string {
	s := map[string]any{
		"automode":    false,
		"matchSpeeds": true,
		"editor":      0,
		"detailsOpen": map[string]bool{
			"info":     false,
			"sensors":  true,
			"energy":   false,
			"schedule": false,
		},
	}
	b, _ := json.Marshal(s)
	return string(b)
}

